// clientRiskRow is the per-client risk scorecard line.
type clientRiskRow struct {
	Client          string `json:"client"`
	Devices         int    `json:"devices"`
	Alerts          int    `json:"alerts"`
	ScreenshotFails int    `json:"screenshotFails"`
	OfflineDevices  int    `json:"offlineDevices"`
	WarrantyExpired int    `json:"warrantyExpired"`
	RiskScore       int    `json:"riskScore"`
}

// pp:data-source local
func newNovelClientRiskCmd(flags *rootFlags) *cobra.Command {
	var flagTop int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "client-risk",
		Short: "Per-client risk scorecard that rolls up screenshot failures, stale backups, open alerts, storage pressure",
		Example: strings.Trim(`
  # Ten highest-risk clients across the fleet
  datto-bcdr-cli client-risk --top 10 --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			if err := validateDataSourceStrategy(flags, "local"); err != nil {
				return err
			}
			if dbPath == "" {
				dbPath = defaultDBPath("datto-bcdr-cli")
			}
			db, err := nvOpenStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer db.Close()

			if !hintIfUnsynced(cmd, db, "") {
				hintIfStale(cmd, db, "", flags.maxAge)
			}

			now := time.Now()

			// Aggregate per client. We load device + agent rows and roll up in
			// Go — clearer than nested SQL date math against ISO-8601 strings.
			agg := map[string]*clientRiskRow{}
			order := []string{}
			get := func(client string) *clientRiskRow {
				if r, ok := agg[client]; ok {
					return r
				}
				r := &clientRiskRow{Client: client}
				agg[client] = r
				order = append(order, client)
				return r
			}

			// Devices: deviceCount, alertSum, offlineDevices, warrantyExpired.
			devRows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.clientCompanyName'), ''),
					json_extract(data,'$.alertCount'),
					json_extract(data,'$.lastSeenDate'),
					json_extract(data,'$.warrantyExpire')
				FROM "device"`)
			if err != nil {
				return fmt.Errorf("querying devices: %w", err)
			}
			defer devRows.Close()
			for devRows.Next() {
				var (
					client      string
					alertCount  sql.NullInt64
					lastSeen    sql.NullString
					warrantyExp sql.NullString
				)
				if err := devRows.Scan(&client, &alertCount, &lastSeen, &warrantyExp); err != nil {
					return fmt.Errorf("scanning device: %w", err)
				}
				r := get(client)
				r.Devices++
				if alertCount.Valid {
					r.Alerts += int(alertCount.Int64)
				}
				if lastSeen.Valid && deviceOffline(lastSeen.String, now, 1) {
					r.OfflineDevices++
				}
				if warrantyExp.Valid && warrantyExpired(warrantyExp.String, now) {
					r.WarrantyExpired++
				}
			}
			if err := devRows.Err(); err != nil {
				return fmt.Errorf("iterating devices: %w", err)
			}
			devRows.Close()

			// Agents joined to devices: count screenshot failures per client.
			agRows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(d.data,'$.clientCompanyName'), ''),
					json_extract(a.data,'$.lastScreenshotAttemptStatus')
				FROM "agent" a
				LEFT JOIN "device" d
					ON json_extract(a.data,'$.deviceSerialNumber') = json_extract(d.data,'$.serialNumber')`)
			if err != nil {
				return fmt.Errorf("querying agents: %w", err)
			}
			defer agRows.Close()
			for agRows.Next() {
				var (
					client sql.NullString
					status sql.NullBool
				)
				if err := agRows.Scan(&client, &status); err != nil {
					return fmt.Errorf("scanning agent: %w", err)
				}
				name := ""
				if client.Valid {
					name = client.String
				}
				// Only count screenshot fails against a known client bucket so
				// an orphan agent (no matching device) doesn't invent a client.
				r, ok := agg[name]
				if !ok {
					continue
				}
				if !(status.Valid && status.Bool) {
					r.ScreenshotFails++
				}
			}
			if err := agRows.Err(); err != nil {
				return fmt.Errorf("iterating agents: %w", err)
			}
			agRows.Close()

			results := make([]clientRiskRow, 0, len(order))
			for _, c := range order {
				r := agg[c]
				r.RiskScore = r.Alerts*2 + r.ScreenshotFails*3 + r.WarrantyExpired*2 + r.OfflineDevices*4
				results = append(results, *r)
			}

			// ORDER BY riskScore DESC, stable on client name for determinism.
			sort.SliceStable(results, func(i, j int) bool {
				if results[i].RiskScore != results[j].RiskScore {
					return results[i].RiskScore > results[j].RiskScore
				}
				return results[i].Client < results[j].Client
			})

			if flagTop > 0 && len(results) > flagTop {
				results = results[:flagTop]
			}

			return flags.printJSON(cmd, results)
		},
	}
	cmd.Flags().IntVar(&flagTop, "top", 0, "Show only the top N highest-risk clients (0 = all)")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (defaults to standard location)")
	return cmd
}

// deviceOffline reports whether an ISO-8601 lastSeenDate is older than
// thresholdDays before now. Unparseable dates are treated as offline so a
// malformed/missing check-in surfaces rather than hides.
func deviceOffline(lastSeen string, now time.Time, thresholdDays int) bool {
	t, ok := parseFlexibleTime(lastSeen)
	if !ok {
		return true
	}
	return now.Sub(t) > time.Duration(thresholdDays)*24*time.Hour
}

// warrantyExpired reports whether a YYYY-MM-DD (or ISO) warranty date is in
// the past. Unparseable dates are treated as not-expired to avoid inflating
// risk on garbage input.
func warrantyExpired(warranty string, now time.Time) bool {
	t, ok := parseFlexibleTime(warranty)
	if !ok {
		return false
	}
	return t.Before(now)
}

// parseFlexibleTime parses the date/time shapes the Datto store emits:
// full RFC3339, and bare YYYY-MM-DD dates. Bare dates anchor to UTC midnight.
func parseFlexibleTime(s string) (time.Time, bool) {
	if s == "" {
		return time.Time{}, false
	}
	layouts := []string{
		time.RFC3339,
		"2006-01-02T15:04:05",
		"2006-01-02",
	}
	for _, l := range layouts {
		if t, err := time.Parse(l, s); err == nil {
			return t, true
		}
	}
	return time.Time{}, false
}
